def build_default_router(logger: logging.Logger) -> MessageRouter:
    router = MessageRouter()

    def handle_email(payload: Dict[str, Any], ctx: Dict[str, Any]) -> None:
        to = payload.get("to")
        subject = payload.get("subject")
        body = payload.get("body")
        if not to or not subject:
            raise MessageProcessingError("email job missing required fields: to, subject")
        logger.info("email job to=%s subject=%s message_id=%s", to, subject, ctx["message_id"])
        _ = body

    def handle_webhook(payload: Dict[str, Any], ctx: Dict[str, Any]) -> None:
        url = payload.get("url")
        method = (payload.get("method") or "POST").upper()
        if not url:
            raise MessageProcessingError("webhook job missing required field: url")
        logger.info("webhook job url=%s method=%s message_id=%s", url, method, ctx["message_id"])

    def handle_reindex(payload: Dict[str, Any], ctx: Dict[str, Any]) -> None:
        index = payload.get("index")
        entity_id = payload.get("id")
        if not index or entity_id is None:
            raise MessageProcessingError("reindex job missing required fields: index, id")
        logger.info("reindex job index=%s id=%s message_id=%s", index, entity_id, ctx["message_id"])

    def default_handler(payload: Dict[str, Any], ctx: Dict[str, Any]) -> None:
        logger.warning("unhandled message type payload_keys=%s message_id=%s", list(payload.keys()), ctx["message_id"])
        raise MessageProcessingError("unhandled message type")

    router.register("email", handle_email)
    router.register("webhook", handle_webhook)
    router.register("reindex", handle_reindex)
    router.set_default(default_handler)
    return router


